#include <stdio.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int L, R;
        scanf("%d %d", &L, &R);
        long long ans = 0;
        for (int i = L; i <= R; i++) {
            if (i % 2 == 1) ans = (ans + 26) % MOD;
            else ans = (ans + 1) % MOD;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

