import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int L = sc.nextInt();
            int R = sc.nextInt();
            long ans = 0;
            for (int i = L; i <= R; i++) {
                if (i % 2 == 1) ans = (ans + 26) % 1000000007;
                else ans = (ans + 1) % 1000000007;
            }
            System.out.println(ans);
        }
    }
}

